INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, 1, "", 11, 105831, "うわぁ～…！\n大きくなりすぎて\nやばいですね☆", "", "", "", "", 1010020);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 91, 0, "", "", "", "", "", 1010021);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, 1, "", 11, 105931, "うえきちゃんが\nどこまで続くのか\n分からないほどです", "", "", "", "", 1010022);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 91, 0, "", "", "", "", "", 1010023);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, 1, "", 11, 112631, "こういうのってさ\n上がどうなってるか\n見てみたいよね！", "", "", "", "", 1010024);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 91, 0, "", "", "", "", "", 1010025);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, 1, "", 11, 112531, "確かにね…それに\nこうなった理由も\n分かるかも", "", "", "", "", 1010026);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 91, 0, "", "", "", "", "", 1010027);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, 1, "", 11, 106031, "ま、興味はあるし\n付き合ってあげるわ", "", "", "", "", 1010028);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 91, 0, "", "", "", "", "", 1010029);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES (10, 1, "", 11, 112431, "はい♪みなさんで\n頂上を目指して\n頑張りましょう！", "", "", "", "", 1010030);
INSERT INTO `v1_81d453b10cb1d8e00703478940bf3b9d02909fc2493abee3378854d04f8813fc` VALUES ("", 1, "", 91, 0, "", "", "", "", "", 1010031);
